fn check_semantic_warnings(config: &MoltisConfig, diagnostics: &mut Vec<Diagnostic>) {
    let is_localhost = config.server.bind == "127.0.0.1"
        || config.server.bind == "localhost"
        || config.server.bind == "::1";

    // auth.disabled + non-localhost
    if config.auth.disabled && !is_localhost {
        diagnostics.push(Diagnostic {
            severity: Severity::Warning,
            category: "security",
            path: "auth".into(),
            message: format!(
                "authentication is disabled while binding to {}",
                config.server.bind
            ),
        });
    }

    // TLS disabled + non-localhost
    if !config.tls.enabled && !is_localhost {
        diagnostics.push(Diagnostic {
            severity: Severity::Warning,
            category: "security",
            path: "tls".into(),
            message: format!("TLS is disabled while binding to {}", config.server.bind),
        });
    }

    // TLS cert without key or vice versa
    let has_cert = config.tls.cert_path.is_some();
    let has_key = config.tls.key_path.is_some();
    if has_cert && !has_key {
        diagnostics.push(Diagnostic {
            severity: Severity::Error,
            category: "security",
            path: "tls".into(),
            message: "tls.cert_path is set but tls.key_path is missing".into(),
        });
    }
    if has_key && !has_cert {
        diagnostics.push(Diagnostic {
            severity: Severity::Error,
            category: "security",
            path: "tls".into(),
            message: "tls.key_path is set but tls.cert_path is missing".into(),
        });
    }

    // Sandbox mode off
    if config.tools.exec.sandbox.mode == "off" {
        diagnostics.push(Diagnostic {
            severity: Severity::Warning,
            category: "security",
            path: "tools.exec.sandbox.mode".into(),
            message: "sandbox mode is disabled — commands run without isolation".into(),
        });
    }

    // Loop limit must be positive to avoid immediate run failures.
    if config.tools.agent_max_iterations == 0 {
        diagnostics.push(Diagnostic {
            severity: Severity::Error,
            category: "invalid-value",
            path: "tools.agent_max_iterations".into(),
            message: "tools.agent_max_iterations must be at least 1".into(),
        });
    }

    if config.mcp.request_timeout_secs == 0 {
        diagnostics.push(Diagnostic {
            severity: Severity::Error,
            category: "invalid-value",
            path: "mcp.request_timeout_secs".into(),
            message: "mcp.request_timeout_secs must be at least 1".into(),
        });
    }

    for (name, server) in &config.mcp.servers {
        if server.request_timeout_secs == Some(0) {
            diagnostics.push(Diagnostic {
                severity: Severity::Error,
                category: "invalid-value",
                path: format!("mcp.servers.{name}.request_timeout_secs"),
                message: "mcp server request_timeout_secs must be at least 1".into(),
            });
        }
    }

    // agents.default_preset should reference an existing preset key.
    if let Some(default_preset) = config.agents.default_preset.as_deref()
        && !config.agents.presets.contains_key(default_preset)
    {
        diagnostics.push(Diagnostic {
            severity: Severity::Warning,
            category: "unknown-field",
            path: "agents.default_preset".into(),
            message: format!(
                "default preset \"{default_preset}\" is not defined in agents.presets"
            ),
        });

}

/// MCP protocol version we implement.
pub const PROTOCOL_VERSION: &str = "2024-11-05";

// ── Transport Errors ──────────────────────────────────────────────────

/// Typed manager errors for MCP lifecycle/auth flows.
#[derive(Debug, thiserror::Error)]
pub enum McpManagerError {
    /// Server requires OAuth before it can be started.
    #[error("MCP server '{server}' requires OAuth authentication")]
    OAuthRequired { server: String },
    /// OAuth callback state did not match any pending flow.
    #[error("unknown or expired MCP OAuth state")]
    OAuthStateNotFound,
    /// Operation requires an SSE server.
    #[error("MCP server '{server}' is not configured for SSE transport")]
    NotSseTransport { server: String },
    /// Operation requires an SSE URL.
    #[error("MCP server '{server}' is missing an SSE URL")]
    MissingSseUrl { server: String },
    /// Server was not found in the MCP registry.
    #[error("MCP server '{server}' not found in registry")]
    ServerNotFound { server: String },
}

/// Typed transport errors for MCP SSE connections.
///
/// Used by `SseTransport` to distinguish recoverable auth errors (401)

pub struct McpServerEntry {
    /// Command to spawn the server process (stdio transport).
    #[serde(default)]
    pub command: String,
    /// Arguments to the command.
    #[serde(default)]
    pub args: Vec<String>,
    /// Environment variables to set for the process.
    #[serde(default)]
    pub env: HashMap<String, String>,
    /// Whether this server is enabled. Defaults to true.
    #[serde(default = "default_true")]
    pub enabled: bool,
    /// Optional per-server MCP request timeout override in seconds.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub request_timeout_secs: Option<u64>,
    /// Transport type: "stdio" (default), "sse", or "streamable-http".
    #[serde(default)]
    pub transport: String,
    /// URL for SSE/Streamable HTTP transport. Required when `transport` is "sse" or "streamable-http".
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub url: Option<String>,
    /// Custom headers for remote HTTP/SSE transport.
    #[serde(default)]
    pub headers: HashMap<String, String>,
    /// Manual OAuth override for servers that don't support standard discovery.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub oauth: Option<McpOAuthOverrideEntry>,
    /// Custom display name for the server (shown in UI instead of technical ID).
    #[serde(default, skip_serializing_if = "Option::is_none")]

